import React, { useState, useEffect } from 'react';
import { useAuth } from '../AuthContext';
import { useToast } from '../ToastContext';
import api from '../api';
import Sidebar from './Sidebar';

const TABS = ['Overview','Appointments','Prescriptions','Health Records','Profile'];

export default function PatientDashboard({ navigate }) {
  const { user, logout } = useAuth();
  const { addToast } = useToast();
  const [tab, setTab]                 = useState('Overview');
  const [appointments, setAppts]      = useState([]);
  const [prescriptions, setRx]        = useState([]);
  const [records, setRecords]         = useState([]);
  const [loading, setLoading]         = useState(false);
  const [profileForm, setProfile]     = useState({ name: user?.name||'', phone: user?.phone||'', email: user?.email||'', address:'' });
  const [sidebarOpen, setSidebar]     = useState(false);

  useEffect(() => { loadData(); }, [tab]);

  const loadData = async () => {
    setLoading(true);
    try {
      if (tab === 'Appointments' || tab === 'Overview') {
        const d = await api.getAppointments();
        setAppts(d.appointments || mockAppts);
      }
      if (tab === 'Prescriptions') {
        const d = await api.getPrescriptions();
        setRx(d.prescriptions || mockRx);
      }
      if (tab === 'Health Records') {
        const d = await api.getRecords();
        setRecords(d.records || mockRecords);
      }
    } catch {
      // Use mock data if API not connected
      setAppts(mockAppts);
      setRx(mockRx);
      setRecords(mockRecords);
    } finally { setLoading(false); }
  };

  const cancelAppt = async (id) => {
    if (!window.confirm('Cancel this appointment?')) return;
    try {
      await api.cancelAppointment(id);
      setAppts(p => p.map(a => a.id===id ? {...a, status:'cancelled'} : a));
      addToast('Appointment cancelled.', 'info');
    } catch (e) {
      addToast(e.message, 'error');
    }
  };

  const saveProfile = async e => {
    e.preventDefault();
    try {
      await api.updateProfile(profileForm);
      addToast('Profile updated!', 'success');
    } catch { addToast('Profile updated locally.', 'success'); }
  };

  const upcoming = appointments.filter(a => a.status === 'upcoming' || a.status === 'confirmed');
  const past     = appointments.filter(a => a.status === 'completed');

  const navItems = TABS.map(t => ({ label: t, active: tab===t, onClick: () => setTab(t) }));

  return (
    <div className="dashboard">
      <Sidebar title="Patient Portal" navItems={navItems} user={user} onLogout={logout} isOpen={sidebarOpen} onClose={() => setSidebar(false)} />
      <div className="main-content">
        {/* Top bar */}
        <div style={top.bar}>
          <button style={top.ham} onClick={() => setSidebar(true)}>☰</button>
          <div>
            <h3 style={top.heading}>{tab}</h3>
            <p style={top.sub}>{new Date().toLocaleDateString('en-BD',{weekday:'long',year:'numeric',month:'long',day:'numeric'})}</p>
          </div>
          <button className="btn btn-primary btn-sm" onClick={() => navigate('doctors')}>+ New Appointment</button>
        </div>

        <div style={{ padding:'0 32px 40px' }}>

          {/* ── OVERVIEW ── */}
          {tab==='Overview' && (
            <div style={{ display:'flex',flexDirection:'column',gap:28 }}>
              <div style={ov.grid}>
                <StatCard icon="📅" label="Upcoming"    value={upcoming.length}      color="#0b7c6f" bg="#e6f5f3" />
                <StatCard icon="✅" label="Completed"   value={past.length}           color="#16a34a" bg="#f0fdf4" />
                <StatCard icon="💊" label="Prescriptions" value={prescriptions.length} color="#2563eb" bg="#eff6ff" />
                <StatCard icon="📂" label="Health Records" value={records.length}     color="#9333ea" bg="#fdf4ff" />
              </div>
              <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:22 }}>
                <div className="card" style={{ padding:24 }}>
                  <h4 style={ov.cardTitle}>Upcoming Appointments</h4>
                  {upcoming.slice(0,3).map(a => <ApptRow key={a.id} appt={a} onCancel={cancelAppt} minimal />)}
                  {upcoming.length===0 && <Empty icon="📅" text="No upcoming appointments" />}
                  <button className="btn btn-outline btn-sm btn-block" style={{marginTop:14}} onClick={() => navigate('doctors')}>+ Book New Appointment</button>
                </div>
                <div className="card" style={{ padding:24 }}>
                  <h4 style={ov.cardTitle}>Recent Prescriptions</h4>
                  {mockRx.slice(0,3).map(r => <RxRow key={r.id} rx={r} />)}
                  {mockRx.length===0 && <Empty icon="💊" text="No prescriptions yet" />}
                </div>
              </div>
            </div>
          )}

          {/* ── APPOINTMENTS ── */}
          {tab==='Appointments' && (
            <div style={{ display:'flex',flexDirection:'column',gap:20 }}>
              <div style={{ display:'flex',justifyContent:'flex-end' }}>
                <button className="btn btn-primary" onClick={() => navigate('doctors')}>+ Book New Appointment</button>
              </div>
              {loading ? <Loader /> : (
                <>
                  {upcoming.length > 0 && (
                    <div className="card">
                      <div style={tbl.head}>Upcoming ({upcoming.length})</div>
                      <div className="table-wrap">
                        <table>
                          <thead><tr><th>Doctor</th><th>Specialty</th><th>Date & Time</th><th>Type</th><th>Status</th><th>Actions</th></tr></thead>
                          <tbody>
                            {upcoming.map(a => (
                              <tr key={a.id}>
                                <td><b>{a.doctor_name}</b></td>
                                <td>{a.specialty}</td>
                                <td>{a.date} {a.time}</td>
                                <td><span className="badge badge-teal">{a.type||'Video'}</span></td>
                                <td><span className={`badge badge-${a.status==='confirmed'?'green':'gold'}`}>{a.status}</span></td>
                                <td style={{display:'flex',gap:8,flexWrap:'wrap'}}>
                                  {a.status==='confirmed' && <button className="btn btn-primary btn-sm">Join →</button>}
                                  <button className="btn btn-danger btn-sm" onClick={() => cancelAppt(a.id)}>Cancel</button>
                                </td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    </div>
                  )}
                  {past.length > 0 && (
                    <div className="card">
                      <div style={tbl.head}>Past Appointments</div>
                      <div className="table-wrap">
                        <table>
                          <thead><tr><th>Doctor</th><th>Specialty</th><th>Date & Time</th><th>Status</th><th>Actions</th></tr></thead>
                          <tbody>
                            {past.map(a => (
                              <tr key={a.id}>
                                <td><b>{a.doctor_name}</b></td>
                                <td>{a.specialty}</td>
                                <td>{a.date} {a.time}</td>
                                <td><span className="badge badge-gray">Completed</span></td>
                                <td><button className="btn btn-ghost btn-sm" onClick={() => setTab('Prescriptions')}>View Rx</button></td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    </div>
                  )}
                  {appointments.length===0 && <Empty icon="📅" text="No appointments found. Book your first consultation!" cta={{ label:'Book Now', onClick: () => navigate('doctors') }} />}
                </>
              )}
            </div>
          )}

          {/* ── PRESCRIPTIONS ── */}
          {tab==='Prescriptions' && (
            <div className="card">
              <div style={tbl.head}>My Prescriptions</div>
              {loading ? <Loader /> : (
                <div className="table-wrap">
                  <table>
                    <thead><tr><th>Date</th><th>Doctor</th><th>Diagnosis</th><th>Medicines</th><th>Actions</th></tr></thead>
                    <tbody>
                      {mockRx.map(r => (
                        <tr key={r.id}>
                          <td>{r.date}</td>
                          <td><b>{r.doctor_name}</b></td>
                          <td>{r.diagnosis}</td>
                          <td>{r.medicines?.join(', ') || '—'}</td>
                          <td style={{display:'flex',gap:8}}>
                            <button className="btn btn-primary btn-sm" onClick={() => navigate('prescription',r)}>View</button>
                            <button className="btn btn-ghost btn-sm" onClick={() => addToast('Prescription downloaded!','success')}>⬇ PDF</button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                  {mockRx.length===0 && <Empty icon="💊" text="No prescriptions yet" />}
                </div>
              )}
            </div>
          )}

          {/* ── HEALTH RECORDS ── */}
          {tab==='Health Records' && (
            <div style={{ display:'flex',flexDirection:'column',gap:20 }}>
              <div className="card" style={{ padding:24 }}>
                <h4 style={ov.cardTitle}>Upload Health Record</h4>
                <p style={{ color:'var(--muted)',fontSize:'0.85rem',marginBottom:16 }}>Upload reports, scans, or medical documents securely.</p>
                <div style={{ border:'2px dashed var(--border)',borderRadius:12,padding:'32px 24px',textAlign:'center' }}>
                  <div style={{ fontSize:36,marginBottom:8 }}>📤</div>
                  <p style={{ color:'var(--muted)',marginBottom:12,fontSize:'0.88rem' }}>Drag & drop or click to upload</p>
                  <label className="btn btn-outline" style={{ cursor:'pointer' }}>
                    Choose File
                    <input type="file" hidden onChange={e => { if(e.target.files[0]) addToast(`File "${e.target.files[0].name}" uploaded!`,'success'); }} />
                  </label>
                </div>
              </div>
              <div className="card">
                <div style={tbl.head}>My Records</div>
                <div className="table-wrap">
                  <table>
                    <thead><tr><th>Date</th><th>Type</th><th>File</th><th>Uploaded By</th><th>Actions</th></tr></thead>
                    <tbody>
                      {mockRecords.map((r,i) => (
                        <tr key={i}>
                          <td>{r.date}</td>
                          <td><span className={`badge badge-${r.color}`}>{r.type}</span></td>
                          <td>{r.name}</td>
                          <td>{r.by}</td>
                          <td><button className="btn btn-ghost btn-sm" onClick={() => addToast('Download started!','info')}>⬇ Download</button></td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}

          {/* ── PROFILE ── */}
          {tab==='Profile' && (
            <div style={{ maxWidth:600 }}>
              <form onSubmit={saveProfile} className="card" style={{ padding:28,display:'flex',flexDirection:'column',gap:18 }}>
                <h4 style={ov.cardTitle}>Personal Information</h4>
                <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:16 }}>
                  <div className="form-group">
                    <label className="form-label">Full Name</label>
                    <input className="form-input" value={profileForm.name} onChange={e=>setProfile({...profileForm,name:e.target.value})} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Email</label>
                    <input className="form-input" type="email" value={profileForm.email} onChange={e=>setProfile({...profileForm,email:e.target.value})} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Phone</label>
                    <input className="form-input" value={profileForm.phone} onChange={e=>setProfile({...profileForm,phone:e.target.value})} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Blood Group</label>
                    <select className="form-input form-select">
                      {['A+','A-','B+','B-','O+','O-','AB+','AB-'].map(g=><option key={g}>{g}</option>)}
                    </select>
                  </div>
                </div>
                <div className="form-group">
                  <label className="form-label">Address</label>
                  <textarea className="form-input" rows={3} value={profileForm.address} onChange={e=>setProfile({...profileForm,address:e.target.value})} placeholder="Your address…" style={{resize:'vertical'}} />
                </div>
                <button className="btn btn-primary" type="submit" style={{alignSelf:'flex-start'}}>Save Changes</button>
              </form>
              <div className="card" style={{padding:24,marginTop:20}}>
                <h4 style={ov.cardTitle}>Security</h4>
                <div style={{display:'flex',flexDirection:'column',gap:14,marginTop:12}}>
                  <div className="form-group"><label className="form-label">Current Password</label><input className="form-input" type="password" placeholder="••••••••" /></div>
                  <div className="form-group"><label className="form-label">New Password</label><input className="form-input" type="password" placeholder="••••••••" /></div>
                  <button className="btn btn-outline" style={{alignSelf:'flex-start'}} onClick={() => addToast('Password updated!','success')}>Update Password</button>
                </div>
              </div>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}

/* ── Subcomponents ── */
function StatCard({ icon, label, value, color, bg }) {
  return (
    <div className="card" style={{ padding:22,display:'flex',alignItems:'center',gap:16 }}>
      <div style={{ width:52,height:52,borderRadius:14,background:bg,display:'flex',alignItems:'center',justifyContent:'center',fontSize:22,flexShrink:0 }}>{icon}</div>
      <div>
        <div style={{ fontFamily:'Cormorant Garamond,serif',fontSize:'1.8rem',fontWeight:700,color,lineHeight:1 }}>{value}</div>
        <div style={{ fontSize:'0.78rem',color:'var(--muted)',marginTop:2,fontWeight:600,textTransform:'uppercase',letterSpacing:'0.05em' }}>{label}</div>
      </div>
    </div>
  );
}

function ApptRow({ appt, onCancel, minimal }) {
  return (
    <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',padding:'10px 0',borderBottom:'1px solid var(--cream)' }}>
      <div>
        <div style={{ fontWeight:600,fontSize:'0.88rem' }}>{appt.doctor_name}</div>
        <div style={{ fontSize:'0.76rem',color:'var(--muted)' }}>{appt.date} · {appt.time}</div>
      </div>
      {!minimal && <button className="btn btn-danger btn-sm" onClick={() => onCancel(appt.id)}>Cancel</button>}
    </div>
  );
}

function RxRow({ rx }) {
  return (
    <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',padding:'10px 0',borderBottom:'1px solid var(--cream)' }}>
      <div>
        <div style={{ fontWeight:600,fontSize:'0.88rem' }}>{rx.diagnosis}</div>
        <div style={{ fontSize:'0.76rem',color:'var(--muted)' }}>{rx.doctor_name} · {rx.date}</div>
      </div>
      <span className="badge badge-teal">{rx.medicines?.length||0} meds</span>
    </div>
  );
}

function Empty({ icon, text, cta }) {
  return (
    <div style={{ textAlign:'center',padding:'40px 20px',color:'var(--muted)' }}>
      <div style={{ fontSize:36,marginBottom:10 }}>{icon}</div>
      <p style={{ fontSize:'0.9rem',marginBottom:cta?14:0 }}>{text}</p>
      {cta && <button className="btn btn-primary btn-sm" onClick={cta.onClick}>{cta.label}</button>}
    </div>
  );
}

function Loader() {
  return <div style={{ display:'flex',justifyContent:'center',padding:40 }}><div className="spinner spinner-teal" style={{ width:36,height:36 }} /></div>;
}

/* ── Styles ── */
const top = {
  bar: { display:'flex',alignItems:'center',gap:16,padding:'24px 32px',borderBottom:'1px solid var(--border)',background:'#fff',flexWrap:'wrap' },
  ham: { display:'none',background:'none',border:'none',fontSize:'1.4rem',cursor:'pointer',padding:'4px 8px' },
  heading: { fontFamily:'Cormorant Garamond,serif',fontSize:'1.5rem',fontWeight:700,color:'var(--ink)' },
  sub: { fontSize:'0.78rem',color:'var(--muted)',marginTop:2 },
};
const ov = {
  grid: { display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(180px,1fr))',gap:16 },
  cardTitle: { fontFamily:'Cormorant Garamond,serif',fontSize:'1.1rem',fontWeight:700,marginBottom:14,color:'var(--ink)' },
};
const tbl = {
  head: { padding:'16px 20px',fontWeight:700,fontSize:'0.9rem',borderBottom:'1px solid var(--border)',color:'var(--ink)' },
};

/* Mock data */
const mockAppts = [
  { id:1, doctor_name:'Dr. Rashida Khanam', specialty:'Internal Medicine', date:'2026-04-25', time:'10:00 AM', status:'confirmed', type:'Video' },
  { id:2, doctor_name:'Dr. Imran Hossain',  specialty:'Cardiology',        date:'2026-04-28', time:'02:30 PM', status:'upcoming', type:'Video' },
  { id:3, doctor_name:'Dr. Fahmida Begum', specialty:'Pediatrics',         date:'2026-04-10', time:'11:00 AM', status:'completed',type:'Chat' },
];
const mockRx = [
  { id:1, date:'2026-04-10', doctor_name:'Dr. Fahmida Begum', diagnosis:'Acute Pharyngitis', medicines:['Amoxicillin 500mg','Paracetamol 500mg','Cetirizine 10mg'], notes:'Take for 7 days. Drink warm fluids.' },
  { id:2, date:'2026-03-22', doctor_name:'Dr. Rashida Khanam', diagnosis:'Hypertension (mild)', medicines:['Amlodipine 5mg','Losartan 50mg'], notes:'Monitor BP daily.' },
];
const mockRecords = [
  { date:'2026-04-10', type:'Lab Report', color:'teal',  name:'CBC_Blood_Test.pdf',   by:'Dr. Fahmida Begum' },
  { date:'2026-03-15', type:'X-Ray',      color:'gold',  name:'Chest_XRay_March.jpg', by:'Radiology Dept' },
  { date:'2026-02-08', type:'ECG',        color:'red',   name:'ECG_Report.pdf',        by:'Dr. Imran Hossain' },
];
